import { ALLOWED_CLEARTEXT_HOSTS } from './config';

/**
 * Validates that a URL is safe to call.
 * - HTTPS is always allowed.
 * - HTTP (cleartext) is only allowed for explicitly whitelisted local IoT hosts.
 */
export const validateUrl = (url) => {
  let parsed;
  try {
    parsed = new URL(url);
  } catch (e) {
    throw new NetworkSecurityError(`Invalid URL: ${url}`);
  }

  const protocol = parsed.protocol;
  const hostname = parsed.hostname;

  // HTTPS is always permitted
  if (protocol === 'https:') {
    return true;
  }

  // HTTP is only permitted for whitelisted local IoT hosts
  if (protocol === 'http:') {
    if (!isAllowedCleartextHost(hostname)) {
      throw new NetworkSecurityError(
        `Cleartext HTTP traffic to "${hostname}" is not allowed. ` +
        `Only whitelisted local IoT device addresses may use HTTP. ` +
        `Allowed hosts: ${ALLOWED_CLEARTEXT_HOSTS.join(', ')}`
      );
    }
    return true;
  }

  throw new NetworkSecurityError(`Unsupported protocol: ${protocol}`);
};

export const isAllowedCleartextHost = (hostname) => {
  return ALLOWED_CLEARTEXT_HOSTS.includes(hostname);
};

export const isLocalIoTAddress = (url) => {
  try {
    const parsed = new URL(url);
    const hostname = parsed.hostname;
    // Check if it's a private IP range (192.168.x.x, 10.x.x.x, 172.16-31.x.x)
    return (
      hostname.startsWith('192.168.') ||
      hostname.startsWith('10.') ||
      /^172\.(1[6-9]|2[0-9]|3[01])\./.test(hostname)
    );
  } catch {
    return false;
  }
};

export class NetworkSecurityError extends Error {
  constructor(message) {
    super(message);
    this.name = 'NetworkSecurityError';
  }
}

