const requestInterceptors = [];
const responseInterceptors = [];

export const addRequestInterceptor = (interceptor) => {
  requestInterceptors.push(interceptor);
  return () => {
    const index = requestInterceptors.indexOf(interceptor);
    if (index !== -1) requestInterceptors.splice(index, 1);
  };
};

export const addResponseInterceptor = (interceptor) => {
  responseInterceptors.push(interceptor);
  return () => {
    const index = responseInterceptors.indexOf(interceptor);
    if (index !== -1) responseInterceptors.splice(index, 1);
  };
};

export const applyRequestInterceptors = async (url, options) => {
  let currentUrl = url;
  let currentOptions = { ...options };

  for (const interceptor of requestInterceptors) {
    const result = await interceptor(currentUrl, currentOptions);
    if (result) {
      currentUrl = result.url || currentUrl;
      currentOptions = result.options || currentOptions;
    }
  }

  return { url: currentUrl, options: currentOptions };
};

export const applyResponseInterceptors = async (response, url) => {
  let currentResponse = response;

  for (const interceptor of responseInterceptors) {
    currentResponse = await interceptor(currentResponse, url);
  }

  return currentResponse;
};

export const clearInterceptors = () => {
  requestInterceptors.length = 0;
  responseInterceptors.length = 0;
};

