export const DEFAULT_RETRY_CONFIG = {
  maxRetries: 3,
  baseDelay: 1000,
  maxDelay: 10000,
  retryableStatusCodes: [408, 429, 500, 502, 503, 504],
  retryableMethods: ['GET', 'HEAD', 'OPTIONS', 'PUT', 'DELETE'],
};

export const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

export const getRetryDelay = (attempt, config = DEFAULT_RETRY_CONFIG) => {
  // Exponential backoff with jitter
  const exponentialDelay = config.baseDelay * Math.pow(2, attempt);
  const jitter = Math.random() * config.baseDelay;
  return Math.min(exponentialDelay + jitter, config.maxDelay);
};

export const shouldRetry = (error, response, method, attempt, config = DEFAULT_RETRY_CONFIG) => {
  if (attempt >= config.maxRetries) return false;

  const upperMethod = (method || 'GET').toUpperCase();
  if (!config.retryableMethods.includes(upperMethod)) return false;

  // Retry on network errors
  if (error && !response) return true;

  // Retry on specific status codes
  if (response && config.retryableStatusCodes.includes(response.status)) return true;

  return false;
};

