import { API_BASE_URL, DEFAULT_TIMEOUT, API_VERSION } from './config';
import { getAuthHeaders } from './headers';
import { validateUrl } from './security';
import { ApiError, NetworkUnavailableError } from './errors';
import { fetchWithTimeout } from './fetchWithTimeout';
import { applyRequestInterceptors, applyResponseInterceptors } from './interceptors';
import { shouldRetry, getRetryDelay, sleep, DEFAULT_RETRY_CONFIG } from './retryPolicy';

const buildUrl = (endpoint) => {
  const cleanEndpoint = endpoint.startsWith('/') ? endpoint : `/${endpoint}`;
  return `${API_BASE_URL}/${API_VERSION}${cleanEndpoint}`;
};

const buildQueryString = (params) => {
  if (!params || Object.keys(params).length === 0) return '';
  const searchParams = new URLSearchParams();
  Object.entries(params).forEach(([key, value]) => {
    if (value !== null && value !== undefined) {
      searchParams.append(key, String(value));
    }
  });
  return `?${searchParams.toString()}`;
};

const parseResponse = async (response) => {
  const contentType = response.headers.get('content-type') || '';

  if (contentType.includes('application/json')) {
    return response.json();
  }

  if (contentType.includes('text/')) {
    return response.text();
  }

  // Try JSON first, fall back to text
  const text = await response.text();
  try {
    return JSON.parse(text);
  } catch {
    return text;
  }
};

const executeRequest = async (url, options, retryConfig = DEFAULT_RETRY_CONFIG) => {
  // Validate URL security policy
  validateUrl(url);

  // Apply request interceptors
  const intercepted = await applyRequestInterceptors(url, options);
  const finalUrl = intercepted.url;
  const finalOptions = intercepted.options;

  let lastError = null;
  let lastResponse = null;

  for (let attempt = 0; attempt <= retryConfig.maxRetries; attempt++) {
    try {
      if (attempt > 0) {
        const delay = getRetryDelay(attempt - 1, retryConfig);
        console.log(`[API] Retry attempt ${attempt} for ${finalUrl} after ${Math.round(delay)}ms`);
        await sleep(delay);
      }

      const response = await fetchWithTimeout(
        finalUrl,
        finalOptions,
        finalOptions.timeout || DEFAULT_TIMEOUT
      );

      // Apply response interceptors
      const interceptedResponse = await applyResponseInterceptors(response, finalUrl);

      if (!interceptedResponse.ok) {
        const errorBody = await parseResponse(interceptedResponse).catch(() => null);

        if (shouldRetry(null, interceptedResponse, finalOptions.method, attempt, retryConfig)) {
          lastResponse = interceptedResponse;
          lastError = new ApiError(
            `API request failed with status ${interceptedResponse.status}`,
            interceptedResponse.status,
            errorBody,
            finalUrl
          );
          continue;
        }

        throw new ApiError(
          errorBody?.message || `API request failed with status ${interceptedResponse.status}`,
          interceptedResponse.status,
          errorBody,
          finalUrl
        );
      }

      const data = await parseResponse(interceptedResponse);

      return {
        data,
        status: interceptedResponse.status,
        headers: interceptedResponse.headers,
        ok: true,
      };
    } catch (error) {
      if (error instanceof ApiError) throw error;

      lastError = error;

      if (shouldRetry(error, null, finalOptions.method, attempt, retryConfig)) {
        continue;
      }

      if (error.message?.includes('Network request failed')) {
        throw new NetworkUnavailableError();
      }

      throw error;
    }
  }

  // All retries exhausted
  if (lastError) throw lastError;
  throw new ApiError('Request failed after all retries', lastResponse?.status, null, finalUrl);
};

export const apiClient = {
  get: (endpoint, params = {}, options = {}) => {
    const queryString = buildQueryString(params);
    const url = `${buildUrl(endpoint)}${queryString}`;

    return executeRequest(url, {
      method: 'GET',
      headers: { ...getAuthHeaders(), ...options.headers },
      ...options,
    }, options.retryConfig);
  },

  post: (endpoint, body = {}, options = {}) => {
    const url = buildUrl(endpoint);

    return executeRequest(url, {
      method: 'POST',
      headers: { ...getAuthHeaders(), ...options.headers },
      body: JSON.stringify(body),
      ...options,
    }, options.retryConfig);
  },

  put: (endpoint, body = {}, options = {}) => {
    const url = buildUrl(endpoint);

    return executeRequest(url, {
      method: 'PUT',
      headers: { ...getAuthHeaders(), ...options.headers },
      body: JSON.stringify(body),
      ...options,
    }, options.retryConfig);
  },

  patch: (endpoint, body = {}, options = {}) => {
    const url = buildUrl(endpoint);

    return executeRequest(url, {
      method: 'PATCH',
      headers: { ...getAuthHeaders(), ...options.headers },
      body: JSON.stringify(body),
      ...options,
    }, options.retryConfig);
  },

  delete: (endpoint, options = {}) => {
    const url = buildUrl(endpoint);

    return executeRequest(url, {
      method: 'DELETE',
      headers: { ...getAuthHeaders(), ...options.headers },
      ...options,
    }, options.retryConfig);
  },

  upload: (endpoint, formData, options = {}) => {
    const url = buildUrl(endpoint);
    const headers = { ...getAuthHeaders(), ...options.headers };
    // Remove Content-Type to let fetch set it with boundary for multipart
    delete headers['Content-Type'];

    return executeRequest(url, {
      method: 'POST',
      headers,
      body: formData,
      ...options,
    }, options.retryConfig);
  },
};

