import { IOT_TIMEOUT, ALLOWED_CLEARTEXT_HOSTS } from './config';
import { getIoTHeaders } from './headers';
import { validateUrl, isLocalIoTAddress, NetworkSecurityError } from './security';
import { IoTDeviceError, NetworkUnavailableError } from './errors';
import { fetchWithTimeout } from './fetchWithTimeout';

const buildIoTUrl = (deviceIp, endpoint, port = 80) => {
  const cleanEndpoint = endpoint.startsWith('/') ? endpoint : `/${endpoint}`;
  // IoT devices on local network use HTTP (cleartext) since they lack HTTPS
  return `http://${deviceIp}:${port}${cleanEndpoint}`;
};

const validateDeviceAddress = (deviceIp) => {
  if (!ALLOWED_CLEARTEXT_HOSTS.includes(deviceIp)) {
    throw new NetworkSecurityError(
      `Device IP "${deviceIp}" is not in the allowed cleartext hosts list. ` +
      `Add it to ALLOWED_CLEARTEXT_HOSTS in config.js to permit HTTP access.`
    );
  }

  // Double-check it's actually a local/private IP
  const fullUrl = `http://${deviceIp}`;
  if (!isLocalIoTAddress(fullUrl)) {
    throw new NetworkSecurityError(
      `Device IP "${deviceIp}" does not appear to be a private/local network address. ` +
      `Cleartext HTTP is only allowed for local IoT devices.`
    );
  }
};

const executeIoTRequest = async (url, options) => {
  validateUrl(url);

  try {
    const response = await fetchWithTimeout(
      url,
      options,
      options.timeout || IOT_TIMEOUT
    );

    if (!response.ok) {
      let errorBody = null;
      try {
        errorBody = await response.json();
      } catch {
        try {
          errorBody = await response.text();
        } catch {
          // ignore
        }
      }

      throw new IoTDeviceError(
        errorBody?.error || `IoT device returned status ${response.status}`,
        url,
        response.status
      );
    }

    const contentType = response.headers.get('content-type') || '';
    let data;

    if (contentType.includes('application/json')) {
      data = await response.json();
    } else {
      const text = await response.text();
      try {
        data = JSON.parse(text);
      } catch {
        data = text;
      }
    }

    return {
      data,
      status: response.status,
      headers: response.headers,
      ok: true,
    };
  } catch (error) {
    if (error instanceof IoTDeviceError || error instanceof NetworkSecurityError) {
      throw error;
    }

    if (error.name === 'TimeoutError') {
      throw new IoTDeviceError(
        `IoT device at ${url} did not respond within timeout`,
        url,
        null
      );
    }

    if (error.message?.includes('Network request failed')) {
      throw new IoTDeviceError(
        `Cannot reach IoT device at ${url}. Ensure you are on the same network.`,
        url,
        null
      );
    }

    throw error;
  }
};

export const iotClient = {
  /**
   * Discover/ping a device to check if it's reachable
   */
  ping: async (deviceIp, port = 80) => {
    validateDeviceAddress(deviceIp);
    const url = buildIoTUrl(deviceIp, '/ping', port);

    try {
      const result = await executeIoTRequest(url, {
        method: 'GET',
        headers: getIoTHeaders(),
        timeout: 3000, // Short timeout for ping
      });
      return { reachable: true, ...result };
    } catch {
      return { reachable: false, data: null, status: null };
    }
  },

  get: (deviceIp, endpoint, options = {}) => {
    validateDeviceAddress(deviceIp);
    const url = buildIoTUrl(deviceIp, endpoint, options.port);

    return executeIoTRequest(url, {
      method: 'GET',
      headers: { ...getIoTHeaders(), ...options.headers },
      ...options,
    });
  },

  post: (deviceIp, endpoint, body = {}, options = {}) => {
    validateDeviceAddress(deviceIp);
    const url = buildIoTUrl(deviceIp, endpoint, options.port);

    return executeIoTRequest(url, {
      method: 'POST',
      headers: { ...getIoTHeaders(), ...options.headers },
      body: JSON.stringify(body),
      ...options,
    });
  },

  put: (deviceIp, endpoint, body = {}, options = {}) => {
    validateDeviceAddress(deviceIp);
    const url = buildIoTUrl(deviceIp, endpoint, options.port);

    return executeIoTRequest(url, {
      method: 'PUT',
      headers: { ...getIoTHeaders(), ...options.headers },
      body: JSON.stringify(body),
      ...options,
    });
  },

  delete: (deviceIp, endpoint, options = {}) => {
    validateDeviceAddress(deviceIp);
    const url = buildIoTUrl(deviceIp, endpoint, options.port);

    return executeIoTRequest(url, {
      method: 'DELETE',
      headers: { ...getIoTHeaders(), ...options.headers },
      ...options,
    });
  },

  /**
   * Send a command to an IoT device
   */
  sendCommand: (deviceIp, command, params = {}, options = {}) => {
    validateDeviceAddress(deviceIp);
    const url = buildIoTUrl(deviceIp, '/command', options.port);

    return executeIoTRequest(url, {
      method: 'POST',
      headers: { ...getIoTHeaders(), ...options.headers },
      body: JSON.stringify({ command, params, timestamp: Date.now() }),
      ...options,
    });
  },

  /**
   * Get device status/info
   */
  getStatus: (deviceIp, options = {}) => {
    validateDeviceAddress(deviceIp);
    const url = buildIoTUrl(deviceIp, '/status', options.port);

    return executeIoTRequest(url, {
      method: 'GET',
      headers: { ...getIoTHeaders(), ...options.headers },
      ...options,
    });
  },

  /**
   * Scan a range of IPs for devices
   */
  scanNetwork: async (subnet = '192.168.1', startIp = 1, endIp = 254, port = 80) => {
    const discoveredDevices = [];

    // Scan in batches to avoid overwhelming the network
    const batchSize = 20;
    for (let i = startIp; i <= endIp; i += batchSize) {
      const batch = [];
      for (let j = i; j < Math.min(i + batchSize, endIp + 1); j++) {
        const ip = `${subnet}.${j}`;
        if (ALLOWED_CLEARTEXT_HOSTS.includes(ip)) {
          batch.push(
            iotClient.ping(ip, port).then((result) => {
              if (result.reachable) {
                discoveredDevices.push({ ip, port, ...result });
              }
            })
          );
        }
      }
      await Promise.all(batch);
    }

    return discoveredDevices;
  },
};

