import React, { useEffect, useState } from 'react';
import { View, Text, Button, FlatList, StyleSheet, Alert } from 'react-native';
import {
  apiClient,
  iotClient,
  setAuthToken,
  addRequestInterceptor,
  addResponseInterceptor,
  ApiError,
  IoTDeviceError,
  TimeoutError,
  NetworkSecurityError,
} from './networking';

// Setup interceptors once at app startup
const setupInterceptors = () => {
  // Log all outgoing requests
  addRequestInterceptor(async (url, options) => {
    console.log(`[NET] → ${options.method || 'GET'} ${url}`);
    return { url, options };
  });

  // Handle 401 globally (e.g., token refresh)
  addResponseInterceptor(async (response, url) => {
    if (response.status === 401) {
      console.warn('[NET] Received 401 - token may be expired');
      // Could trigger token refresh logic here
    }
    return response;
  });
};

const App = () => {
  const [users, setUsers] = useState([]);
  const [deviceStatus, setDeviceStatus] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    setupInterceptors();
    // Set auth token after login
    setAuthToken('your-jwt-token-here');
  }, []);

  // Example: Fetch users from production API (HTTPS)
  const fetchUsers = async () => {
    setLoading(true);
    try {
      const response = await apiClient.get('/users', { page: 1, limit: 20 });
      setUsers(response.data);
    } catch (error) {
      if (error instanceof ApiError) {
        Alert.alert('API Error', `Status ${error.statusCode}: ${error.message}`);
      } else if (error instanceof TimeoutError) {
        Alert.alert('Timeout', 'The server took too long to respond.');
      } else if (error instanceof NetworkSecurityError) {
        Alert.alert('Security Error', error.message);
      } else {
        Alert.alert('Error', error.message);
      }
    } finally {
      setLoading(false);
    }
  };

  // Example: Create a user via API (HTTPS)
  const createUser = async () => {
    try {
      const response = await apiClient.post('/users', {
        name: 'John Doe',
        email: 'john@example.com',
      });
      Alert.alert('Success', `User created with id: ${response.data.id}`);
    } catch (error) {
      Alert.alert('Error', error.message);
    }
  };

  // Example: Get IoT device status (HTTP - local network)
  const checkDevice = async () => {
    setLoading(true);
    try {
      const pingResult = await iotClient.ping('192.168.1.100');
      if (!pingResult.reachable) {
        Alert.alert('Device Offline', 'Cannot reach the device.');
        return;
      }

      const status = await iotClient.getStatus('192.168.1.100');
      setDeviceStatus(status.data);
    } catch (error) {
      if (error instanceof IoTDeviceError) {
        Alert.alert('Device Error', error.message);
      } else if (error instanceof NetworkSecurityError) {
        Alert.alert('Security Error', error.message);
      } else {
        Alert.alert('Error', error.message);
      }
    } finally {
      setLoading(false);
    }
  };

  // Example: Send command to IoT device (HTTP - local network)
  const toggleDeviceLight = async () => {
    try {
      const result = await iotClient.sendCommand('192.168.1.100', 'toggle_light', {
        brightness: 80,
        color: '#FFFFFF',
      });
      Alert.alert('Command Sent', JSON.stringify(result.data));
    } catch (error) {
      Alert.alert('Error', error.message);
    }
  };

  // Example: This would FAIL - demonstrates security enforcement
  const attemptUnsafeRequest = async () => {
    try {
      // This will throw NetworkSecurityError because 8.8.8.8 is not whitelisted
      await iotClient.get('8.8.8.8', '/test');
    } catch (error) {
      Alert.alert('Blocked!', error.message);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Networking Module Demo</Text>

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>API (HTTPS)</Text>
        <Button title="Fetch Users" onPress={fetchUsers} disabled={loading} />
        <Button title="Create User" onPress={createUser} disabled={loading} />
      </View>

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>IoT Devices (HTTP - Local)</Text>
        <Button title="Check Device" onPress={checkDevice} disabled={loading} />
        <Button title="Toggle Light" onPress={toggleDeviceLight} disabled={loading} />
        <Button title="Test Security Block" onPress={attemptUnsafeRequest} />
      </View>

      {deviceStatus && (
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>Device Status</Text>
          <Text>{JSON.stringify(deviceStatus, null, 2)}</Text>
        </View>
      )}

      <FlatList
        data={users}
        keyExtractor={(item) => String(item.id)}
        renderItem={({ item }) => (
          <Text style={styles.listItem}>{item.name || item.email}</Text>
        )}
      />
    </View>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1, padding: 20, paddingTop: 60 },
  title: { fontSize: 22, fontWeight: 'bold', marginBottom: 20 },
  section: { marginBottom: 20 },
  sectionTitle: { fontSize: 16, fontWeight: '600', marginBottom: 8 },
  listItem: { padding: 8, borderBottomWidth: 1, borderBottomColor: '#eee' },
});

export default App;